-        }
-        if priority.is_some() {
-            conflicting.push("--priority");
-        }
-        if issue_type.is_some() {
-            conflicting.push("--type");
-        }
-        if team.is_some() {
-            conflicting.push("--team");
-        }
-        if points.is_some() {
-            conflicting.push("--points");
-        }
-        if no_points {
-            conflicting.push("--no-points");
-        }
-        if parent.is_some() {
-            conflicting.push("--parent");
-        }
-        if no_parent {
