-                if let Some(pts) = points {
-                    println!("  points → {pts}");
-                }
-                if no_points {
-                    println!("  points → (clear)");
-                }
-                // Single-key-only fields: team, description, description_stdin, markdown.
-                // Multi-key bulk rejects these flags upstream (C-1 guard), so reaching
