-                }
-            }
-        }
-        return Ok(());
-    }
-
-    // --- Confirmation for large JQL match sets. ---
-    // Safety-net: when --jql is used AND match count > threshold (JQL_CONFIRM_THRESHOLD),
-    // require explicit --yes or interactive confirmation.
