-
-    // --- Multi-key non-label: route through bulk_edit_fields. ---
-    if effective_keys.len() > 1 {
-        return handle_edit_bulk_fields(
-            &effective_keys,
-            summary.as_deref(),
-            priority.as_deref(),
-            issue_type.as_deref(),
